// Multibench main — memory partition.
//
// Builds one binary that runs every "memory" bench (loads, stores, ART loop
// sweep, D-bus streaming) back-to-back under a single STLINK-V3PWR trigger
// window. The bench table comes from src/generated/multibench_tables.h
// (auto-generated by tools/gen_kernels.py).

#include <ento-bench/multi_harness.h>
#include <ento-bench/bench_config.h>

#ifdef STM32_BUILD
#include <ento-mcu/clk_util.h>
#include <ento-mcu/systick_config.h>
#endif

#include "generated/multibench_tables.h"

#include <cstdlib>

extern "C" void initialise_monitor_handles(void);

int main()
{
    initialise_monitor_handles();

#if defined(STM32_BUILD) && !defined(GEM5_SIM)
    sys_clk_cfg();
#endif

#ifdef STM32_BUILD
    SysTick_Setup();
    __enable_irq();
#endif

#if !defined(GEM5_SIM)
    ENTO_BENCH_SETUP();
#endif
    ENTO_BENCH_PRINT_CONFIG();

    EntoBench::MultiHarness h(BENCHES_MEMORY, "multibench_memory");
    h.setup();
    h.run();
    h.teardown();

    std::exit(0);
    return 0;
}
